import React from 'react';
import Header from '../components/header/header';
import Footer from '../components/Footer/Footer';
import { ResolvedContentProvider } from '../ppm/util/ResolvedContentContext';
import { useCMS } from '../contexts/CMSContext';
import { STATIC_COLLECTIONS } from '../contexts/db/collections';
import { STATIC_MUSIC_ALBUMS } from '../contexts/db/music-albums';
import { STATIC_EDUCATION } from '../contexts/db/education';
import { STATIC_NEWS } from '../contexts/db/news';

const extractFirstImage = (html?: string) => {
  if (!html) return null;
  const match = html.match(/<img[^>]+src="([^">]+)"/);
  return match ? match[1] : null;
};

interface PostDetailProps {
  pageContext: {
    item?: {
      id?: string | number;
      link?: string;
      title: string;
      subtitle?: string;
      body: string;
      image?: string;
      date?: string;
      category?: string;
      slug?: string;
      audioFile?: string; // Added audioFile to item interface
    };
  };
  location?: any;
}

const PostDetailInner: React.FC<{ staticItem: any, location?: any }> = ({ staticItem, location }) => {
  const { displayData } = useCMS();
  
  let item = staticItem ? { ...staticItem } : null;

  const currentPath = location?.pathname;

  const searchArrays = [
    displayData?.pages?.newsPage?.items,
    displayData?.pages?.home?.newsContent?.items,
    displayData?.pages?.educationPage?.items,
    // Flatten out tracks if dealing with music albums 
    displayData?.pages?.musicPage?.albums?.flatMap(a => a.tracks),
    displayData?.pages?.galleriesPage?.collections,
    displayData?.pages?.galleriesPage?.imageBlogs,
    STATIC_COLLECTIONS,
    STATIC_MUSIC_ALBUMS.flatMap((a: any) => a.tracks || []),
    STATIC_EDUCATION,
    STATIC_NEWS
  ];

  // If item is null or missing info, try to find it by path
  if (!item || !item.title) {
    const slugOrId = currentPath?.split('/').filter(Boolean).pop();
    
    if (slugOrId) {
      for (const arr of searchArrays) {
        if (Array.isArray(arr)) {
          const found = arr.find((i: any) => 
            (i.link && i.link.includes(slugOrId)) ||
            (i.slug && i.slug === slugOrId) ||
            (i.id && String(i.id) === String(slugOrId))
          );
          if (found) {
            const anyFound: any = found;
            item = { 
              ...anyFound, 
              title: anyFound.title || anyFound.name || '',
              body: anyFound.body || anyFound.content || anyFound.lyrics || anyFound.description || '' 
            };
            break;
          }
        }
      }
    }
  } else {
    // Basic enrichment for static items
    for (const arr of searchArrays) {
      if (Array.isArray(arr)) {
        const found = arr.find((i: any) => 
          (i.id && item.id && String(i.id) === String(item.id)) || 
          (i.link && item.link && i.link === item.link) ||
          (i.slug && item.slug && i.slug === item.slug)
        );
        if (found) {
          const anyFound: any = found;
          item = { ...item, ...anyFound, body: anyFound.body || anyFound.content || anyFound.lyrics || item.body };
          break;
        }
      }
    }
  }

  if (!item) {
    return (
      <div className="post-detail-wrapper">
        <Header showHero={true} />
        <div style={{ padding: '100px 20px', textAlign: 'center' }}>
          <h2>Nội dung đang được cập nhật</h2>
          <p>Không tìm thấy nội dung tại {currentPath}</p>
        </div>
        <Footer />
      </div>
    );
  }

  // Function to process body content with ImageKit CDN
  const processContent = (html: string) => {
    if (!html) return '';
    
    // 1. Replace bpkq domain with ImageKit CDN for better performance and to ensure visibility
    let processed = html.replace(
      /http:\/\/bodephatquoc\.org\/wp-content\/uploads\//g, 
      'https://bodephatquoc.org/wp-content/uploads/'
    );

    // 2. Wrap Foogallery style links (common in migrated data) to ensure they show up as a grid
    // Look for clusters of image links and wrap them in foogallery-container
    processed = processed.replace(
      /<a([^>]+)href=["']([^"']+\.(?:jpg|jpeg|png|gif|webp|bmp))["']([^>]*)>\s*<img[^>]+>\s*<\/a>/gi, 
      '<a$1href="$2"$3><img src="$2" loading="lazy" alt="Gallery Image" /></a>'
    );

    // 3. Ensure any direct <img> tags also use the CDN (if not already handled)
    processed = processed.replace(
      /src=["']http:\/\/bodephatquoc\.org\/wp-content\/uploads\/([^"']+)["']/g,
      'src="https://bodephatquoc.org/wp-content/uploads/$1"'
    );

    // 4. Handle plain text line breaks if no HTML tags are present or as a general fallback
    if (processed && !processed.includes('<p>') && !processed.includes('<br')) {
      processed = processed.replace(/\n/g, '<br />');
    } else if (processed) {
      // Even with HTML, we might want to preserve double newlines as paragraphs if they aren't wrapped
      processed = processed.replace(/\n\s*\n/g, '<br /><br />');
    }

    return processed;
  };

  const processedBody = processContent(item.body);

  return (
      <div className="post-detail-wrapper">
        <Header showHero={true} />

        <main className="post-detail-main">
          <article className="post-article">
            <header className="post-header">
              {item.category && (
                <span className="post-category">
                  {item.category}
                </span>
              )}
              <h1 className="post-title">
                {item.title}
              </h1>
              <div className="post-header-underline" />
              {item.date && (
                <p className="post-date">
                  {item.date}
                </p>
              )}
            </header>

            {!processedBody && item.image && (
              <div className="post-image-container">
                <img 
                  src={item.image} 
                  alt={item.title} 
                  className="post-main-image"
                />
              </div>
            )}

            <div className={`post-content-card ${!processedBody ? 'empty-body' : ''}`}>
              {processedBody ? (
                <div 
                  className="post-body-content"
                  dangerouslySetInnerHTML={{ 
                    __html: processedBody
                  }} 
                />
              ) : (
                <div className="post-body-placeholder">
                  {item.image && processedBody === '' ? (
                    <p style={{ textAlign: 'center', color: '#888' }}>
                      Nội dung này hiện đang được cập nhật. Quý khách vui lòng quay lại sau.
                    </p>
                  ) : (
                    <>
                      {item.audioFile && (
                        <div className="post-audio-player" style={{ margin: '30px 0', padding: '20px', background: '#f9f7f2', borderRadius: '12px', border: '1px solid #E6B422' }}>
                          <p style={{ margin: '0 0 10px 0', fontSize: '14px', color: '#888', textTransform: 'uppercase' }}>🎵 Nghe Audio</p>
                          <audio controls style={{ width: '100%', height: '40px' }}>
                            <source src={item.audioFile.startsWith('http') ? item.audioFile : `https://bodephatquoc.org/wp-content/uploads/${item.audioFile}`} type="audio/mpeg" />
                            Trình duyệt của bạn không hỗ trợ trình phát âm thanh.
                          </audio>
                        </div>
                      )}
                      <div className="post-body-content" dangerouslySetInnerHTML={{ __html: item.body }} />
                    </>
                  )}
                </div>
              )}
            </div>
          </article>
        </main>

        <Footer />
      </div>
  );
};

